fn is_private_ip(ip: IpAddr) -> bool {
    match ip {
        IpAddr::V4(ipv4) => {
            ipv4.is_private()
                || ipv4.is_loopback()
                || ipv4.is_link_local()
                || ipv4.is_broadcast()
                || ipv4.is_documentation()
                || ipv4.is_unspecified()
        }
        IpAddr::V6(ipv6) => {
            ipv6.is_loopback() || ipv6.is_unspecified() || ipv6.is_multicast()
        }
    }
}

fn validate_url(url_str: &str) -> Result<Url, String> {
    let url = Url::parse(url_str).map_err(|_| "Invalid URL format")?;

    if !ALLOWED_SCHEMES.contains(url.scheme()) {
        return Err("Only HTTPS URLs are allowed".to_string());
    }

    let host = url.host_str().ok_or("URL must have a host")?;

    if BLOCKED_HOSTS.contains(host) {
        return Err("Access to this host is not allowed".to_string());
    }

    if host.starts_with("169.254.") || host.starts_with("10.") || host.starts_with("192.168.") {
        return Err("Access to private IP ranges is not allowed".to_string());
    }

    if host.starts_with("172.") {
        if let Some(second_octet) = host.split('.').nth(1) {
            if let Ok(num) = second_octet.parse::<u8>() {
                if (16..=31).contains(&num) {
                    return Err("Access to private IP ranges is not allowed".to_string());
                }
            }
        }
    }

    if let Some(domain) = url.domain() {
        if domain.ends_with(".local")
            || domain.ends_with(".internal")
            || domain.ends_with(".localhost")
        {
            return Err("Access to internal domains is not allowed".to_string());
        }
    }

    Ok(url)
}

async fn proxy_handler(Query(params): Query<ProxyParams>) -> Response {
    let url = match validate_url(&params.url) {
        Ok(u) => u,
        Err(e) => {
            return (StatusCode::BAD_REQUEST, format!("Invalid URL: {}", e)).into_response()
        }
    };

    if let Some(host) = url.host_str() {
        if let Ok(addrs) = tokio::net::lookup_host((host, 443)).await {
            for addr in addrs {
                if is_private_ip(addr.ip()) {
                    return (
                        StatusCode::FORBIDDEN,
                        "Access to private IP addresses is not allowed",
                    )
                        .into_response();
                }
            }
        }
    }

    let client = match reqwest::Client::builder()
        .timeout(REQUEST_TIMEOUT)
        .redirect(reqwest::redirect::Policy::limited(3))
        .user_agent("WebhookProxy/1.0")
        .build()
    {
        Ok(c) => c,
        Err(_) => {
            return (StatusCode::INTERNAL_SERVER_ERROR, "Failed to create HTTP client")
                .into_response()
        }
    };

    let response = match client.get(url.as_str()).send().await {
        Ok(r) => r,
        Err(e) => {
            return (
                StatusCode::BAD_GATEWAY,
                format!("Failed to fetch URL: {}", e),
            )
                .into_response()
        }
    };

    let status = response.status();
    let headers = response.headers().clone();

    let content_length = headers
        .get(reqwest::header::CONTENT_LENGTH)
        .and_then(|v| v.to_str().ok())
        .and_then(|v| v.parse::<usize>().ok())
        .unwrap_or(0);

    if content_length > MAX_RESPONSE_SIZE {
        return (StatusCode::PAYLOAD_TOO_LARGE, "Response too large").into_response();
    }

    let body = match response.bytes().await {
        Ok(b) => b,
        Err(e) => {
            return (
                StatusCode::BAD_GATEWAY,
                format!("Failed to read response: {}", e),
            )
                .into_response()
        }
    };

    if body.len() > MAX_RESPONSE_SIZE {
        return (StatusCode::PAYLOAD_TOO_LARGE, "Response too large").into_response();
    }

    let mut response_builder = axum::http::Response::builder().status(status);

    for (key, value) in headers.iter() {
        let key_str = key.as_str();
        if key_str != "transfer-encoding" && key_str != "connection" {
            response_builder = response_builder.header(key, value);
        }
    }

    match response_builder.body(axum::body::Body::from(body)) {
        Ok(r) => r.into_response(),
        Err(_) => (StatusCode::INTERNAL_SERVER_ERROR, "Failed to build response").into_response(),
    }
}

